export function IcoMapDisplay() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Map frame */}
      <rect x="30" y="18" width="140" height="94" rx="8" fill={palette.mid} opacity="0.35" stroke={palette.accent} strokeWidth="2.5" />
      {/* Crosshair lines */}
      <line x1="100" y1="18" x2="100" y2="112" stroke="rgba(255,255,255,0.12)" strokeWidth="1.5" />
      <line x1="30" y1="65" x2="170" y2="65" stroke="rgba(255,255,255,0.12)" strokeWidth="1.5" />
      {/* Location pin */}
      <ellipse cx="100" cy="58" rx="14" ry="14" fill={palette.accent} />
      <ellipse cx="100" cy="58" rx="6" ry="6" fill={palette.dark} />
      <polygon points="100,72 93,58 107,58" fill={palette.accent} />
    </svg>
  );
}
